import uuidfrom sqlalchemy import Column, String, Integer, Float, JSON, ForeignKey, DateTime, funcfrom sqlalchemy.orm import relationshipfrom database import Basedef new_uuid():    return str(uuid.uuid4())class LibraryImage(Base):    __tablename__ = "library_images"    id = Column(String, primary_key=True, default=new_uuid)    url = Column(String, nullable=False)    name = Column(String)    category = Column(String)    past_prices = Column(JSON, default=list)    past_descriptions_en = Column(JSON, default=list)    past_descriptions_zh = Column(JSON, default=list)    created_at = Column(DateTime, server_default=func.now())class Template(Base):    __tablename__ = "templates"    id = Column(String, primary_key=True, default=new_uuid)    name = Column(String, nullable=False)    cells_per_page = Column(Integer, nullable=False)    columns = Column(Integer, nullable=False)    rows = Column(Integer, nullable=False)    page_width_px = Column(Integer, nullable=False)    page_height_px = Column(Integer, nullable=False)    layout_spec = Column(JSON, nullable=False)class Project(Base):    __tablename__ = "projects"    id = Column(String, primary_key=True, default=new_uuid)    name = Column(String, nullable=False)    template_id = Column(String, ForeignKey("templates.id"))    status = Column(String, default="draft")    border_store_name = Column(String)    border_date_range = Column(String)    border_logo_url = Column(String)    border_tagline = Column(String)    border_notes = Column(String)    created_at = Column(DateTime, server_default=func.now())    updated_at = Column(DateTime, server_default=func.now(), onupdate=func.now())    items = relationship("Item", back_populates="project", cascade="all, delete")    cells = relationship("Cell", back_populates="project", cascade="all, delete")class Item(Base):    __tablename__ = "items"    id = Column(String, primary_key=True, default=new_uuid)    project_id = Column(String, ForeignKey("projects.id"))    library_image_id = Column(String, ForeignKey("library_images.id"))    position = Column(Integer, nullable=False)    price_amount = Column(String)    price_unit = Column(String)    price_prefix = Column(String)    description_en = Column(String)    description_zh = Column(String)    notes = Column(String)    image_offset_x = Column(Integer, default=0)    image_offset_y = Column(Integer, default=0)    image_scale = Column(Float, default=1.0)    cell_render_url = Column(String)    project = relationship("Project", back_populates="items")    image = relationship("LibraryImage")    class Cell(Base):    __tablename__ = "cells"    id = Column(String, primary_key=True, default=new_uuid)    project_id = Column(String, ForeignKey("projects.id"))    page_number = Column(Integer, nullable=False)    position_on_page = Column(Integer, nullable=False)    item_id = Column(String, ForeignKey("items.id"), nullable=True)    cell_type = Column(String, default="item")    project = relationship("Project", back_populates="cells")